    "description": "import './QrCode.scss';\r\n \r\nimport {HtmlPageTitle, PageLoader} from '@pivot/hed-ui-lib';\r\n \r\nconst QrCode = () => {\r\n  setTimeout(() => {\r\n    // Identify the user's device and redirect accordingly\r\n    const userAgent = navigator.userAgent.toLowerCase();\r\n \r\n    if (userAgent) {\r\n      let redirectUrl;\r\n      if (userAgent.match(/(iphone|ipod|ipad|appletv)/)) {\r\n        redirectUrl = 'https://apps.apple.com/us/app/bigfuture-school/id6462904878';\r\n      } else if (userAgent.match(/android/)) {\r\n        redirectUrl = 'https://play.google.com/store/apps/details?id=org.collegeboard.pivot';\r\n      } else {\r\n        redirectUrl = 'https://apps.apple.com/us/app/bigfuture-school/id6462904878';\r\n      }\r\n \r\n      window.location.replace(redirectUrl);\r\n    }\r\n \r\n    // TODO: Scott Thomas advised 3 second wait to allow adobe code to load before redirecting\r\n  }, 3000);\r\n \r\n  return (\r\n    <>\r\n      <HtmlPageTitle title='Qr Code' />\r\n \r\n      <div data-testid='qr-code-container' className='container'>\r\n        <h4 style={{display: 'flex', justifyContent: 'center', marginTop: 40}}>\r\n          Redirecting to app download...\r\n        </h4>\r\n        <PageLoader />\r\n      </div>\r\n    </>\r\n  );\r\n};\r\n \r\nexport default QrCode;",
